import React, { useCallback, useEffect, useState } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import useFetch from "../hooks/useFetch";
import Loader from "./utils/Loader";
import Tooltip from "./utils/Tooltip";

const Tasks = () => {
  const authState = useSelector((state) => state.authReducer);
  const [tasks, setTasks] = useState([]);
  const [fetchData, { loading }] = useFetch();

  // ✅ Fetch tasks
  const fetchTasks = useCallback(() => {
    const config = {
      url: "/tasks",
      method: "get",
      headers: {
        Authorization: `Bearer ${authState.token}`, // ✅ FIXED
      },
    };

    fetchData(config, { showSuccessToast: false }).then((data) => {
      console.log("TASKS:", data); // 🔍 debug
      setTasks(data.tasks || []);
    });
  }, [authState.token, fetchData]);

  {tasks.map((task) => (
  <pre key={task.id}>
    {JSON.stringify(task, null, 2)}
  </pre>
))}

  useEffect(() => {
    if (!authState.isLoggedIn) return;
    fetchTasks();
  }, [authState.isLoggedIn, fetchTasks]);

  // ✅ Delete task
  const handleDelete = (id) => {
    const config = {
      url: `/tasks/${id}`,
      method: "delete",
      headers: {
        Authorization: `Bearer ${authState.token}`, // ✅ FIXED
      },
    };

    fetchData(config).then(() => fetchTasks());
  };

  return (
    <div className="my-2 mx-auto max-w-[700px] py-4">
      {tasks.length !== 0 && (
        <h2 className="my-2 ml-2 md:ml-0 text-xl">
          Your tasks ({tasks.length})
        </h2>
      )}

      {loading ? (
        <Loader />
      ) : (
        <div>
          {tasks.length === 0 ? (
            <div className="w-[600px] h-[300px] flex items-center justify-center gap-4">
              <span>No tasks found</span>
              <Link
                to="/tasks/add"
                className="bg-blue-500 text-white hover:bg-blue-600 font-medium rounded-md px-4 py-2"
              >
                + Add new task
              </Link>
            </div>
          ) : (
            tasks.map((task, index) => (
              <div
                key={task.id} // ✅ FIXED (important)
                className="bg-white my-4 p-4 text-gray-600 rounded-md shadow-md"
              >
                <div className="flex items-center">
                  <span className="font-medium">
                    Task #{index + 1}
                  </span>

                  {/* EDIT */}
                  <Tooltip text={"Edit this task"} position={"top"}>
                    <Link
                      to={`/tasks/${task.id}`} // ✅ FIXED
                      className="ml-auto mr-2 text-green-600 cursor-pointer"
                    >
                      <i className="fa-solid fa-pen"></i>
                    </Link>
                  </Tooltip>

                  {/* DELETE */}
                  <Tooltip text={"Delete this task"} position={"top"}>
                    <span
                      className="text-red-500 cursor-pointer"
                      onClick={() => handleDelete(task.id)} // ✅ FIXED
                    >
                      <i className="fa-solid fa-trash"></i>
                    </span>
                  </Tooltip>
                </div>

                {/* TITLE */}
                <div className="font-semibold mt-2">
                  {task.title}
                </div>

                {/* STATUS */}
                <div className="text-sm mt-1">
                  Status:{" "}
                  <span
                    className={
                      task.status === "Completed"
                        ? "text-green-600"
                        : task.status === "In Progress"
                        ? "text-yellow-600"
                        : "text-blue-600"
                    }
                  >
                    {task.status}
                  </span>
                </div>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default Tasks;
